import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import he from '../i18n/he.json';

const API = 'https://pizza-story-backend-u6n0.onrender.com';
const DELIVERY_FEE = 15;
const STORE_ADDRESS = 'רחוב הפיצה 1, תל אביב';

const PROMO_CODES = {
  PIZZA10:  { type: 'percent',  value: 10, label: '10% הנחה' },
  PIZZA20:  { type: 'percent',  value: 20, label: '20% הנחה' },
  FREESHIP: { type: 'delivery', value: 0,  label: 'משלוח חינם' },
};

export default function CheckoutForm() {
  const navigate = useNavigate();
  const cart = JSON.parse(localStorage.getItem('cart') || '{}');
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  const [form, setForm] = useState({
    name:         auth.name || '',
    phone:        auth.phone || '',
    address:      '',
    kitchenNotes: '',
    driverNotes:  '',
    paymentMethod: 'cash',
  });
  const [fulfillmentType, setFulfillmentType] = useState('delivery');
  const [promoInput,      setPromoInput]      = useState('');
  const [appliedPromo,    setAppliedPromo]    = useState(null);
  const [promoError,      setPromoError]      = useState('');
  const [addressPrefilled, setAddressPrefilled] = useState(false);
  const [loading,         setLoading]         = useState(false);
  const [showPromo,       setShowPromo]       = useState(false);

  useEffect(() => {
    if (!auth.phone) return;
    axios
      .get(`${API}/api/orders/history/${auth.phone}`)
      .then(res => {
        const sorted = res.data.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
        const last = sorted[0];
        if (!last) return;
        const lastAddress = last.address || last.deliveryAddress;
        if (lastAddress) {
          setForm(f => ({ ...f, address: lastAddress }));
          setAddressPrefilled(true);
        }
        if (last.name && !auth.name) setForm(f => ({ ...f, name: last.name }));
      })
      .catch(() => {});
  }, []);

  if (!cart.toppings) return null;

  const handleChange = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const applyPromo = () => {
    const code = promoInput.trim().toUpperCase();
    if (PROMO_CODES[code]) {
      setAppliedPromo({ code, ...PROMO_CODES[code] });
      setPromoError('');
    } else {
      setPromoError(he.promo_invalid);
      setAppliedPromo(null);
    }
  };

  const removePromo = () => { setAppliedPromo(null); setPromoInput(''); setPromoError(''); };

  const baseTotal   = cart.total || 30;
  const isFreeShip  = appliedPromo?.type === 'delivery';
  const deliveryFee = fulfillmentType === 'delivery' && !isFreeShip ? DELIVERY_FEE : 0;
  const discountAmt = appliedPromo?.type === 'percent'
    ? Math.round(baseTotal * appliedPromo.value / 100) : 0;
  const finalTotal  = baseTotal + deliveryFee - discountAmt;

  const handleSubmit = async e => {
    e.preventDefault();
    if (fulfillmentType === 'delivery' && !form.address.trim()) {
      alert('יש להכניס כתובת למשלוח');
      return;
    }
    setLoading(true);
    try {
      await axios.post(`${API}/api/orders`, {
        name:           form.name,
        phone:          form.phone,
        customerPhone:  form.phone,
        address:        fulfillmentType === 'delivery' ? form.address : STORE_ADDRESS,
        deliveryAddress: fulfillmentType === 'delivery' ? form.address : '',
        paymentMethod:  form.paymentMethod,
        paymentStatus:  form.paymentMethod === 'cash' ? 'pending_cash' : 'paid',
        fulfillmentType,
        kitchenNotes:   form.kitchenNotes || null,
        driverNotes:    fulfillmentType === 'delivery' ? (form.driverNotes || null) : null,
        couponCode:     appliedPromo?.code || null,
        toppings:       cart.toppings,
        total:          finalTotal,
        createdAt:      new Date().toISOString(),
      });

      if (form.name && !auth.name) {
        localStorage.setItem('pizzaAuth', JSON.stringify({ ...auth, name: form.name }));
      }
      localStorage.removeItem('cart');
      navigate('/success');
    } catch {
      alert('שגיאה בשליחת ההזמנה');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="max-w-md mx-auto min-h-screen bg-gray-50">

      {/* Navy Header */}
      <div className="bg-navy px-5 pt-5 pb-4 flex items-center gap-3">
        <button
          type="button"
          onClick={() => navigate('/cart')}
          className="text-white/70 hover:text-white text-xl transition"
        >
          ←
        </button>
        <h1 className="text-white text-xl font-black">פרטי הזמנה</h1>
      </div>

      <div className="px-4 pt-4 pb-10 space-y-4">

        {/* STEP 1: Fulfillment */}
        <div className="bg-white rounded-2xl shadow-sm p-4">
          <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-3">שלב 1 — איך תקבלו?</p>
          <div className="grid grid-cols-2 gap-3">
            {[
              { key: 'delivery', emoji: '🛵', title: 'משלוח עד הבית', sub: `+${DELIVERY_FEE}₪` },
              { key: 'pickup',   emoji: '🏪', title: 'איסוף עצמי',    sub: 'חינם' },
            ].map(opt => (
              <button
                key={opt.key}
                type="button"
                onClick={() => setFulfillmentType(opt.key)}
                className={`flex flex-col items-center justify-center py-5 rounded-xl border-2 font-bold text-sm transition active:scale-95 ${
                  fulfillmentType === opt.key
                    ? 'border-tomato bg-red-50 text-tomato shadow-sm'
                    : 'border-gray-200 text-gray-500 hover:border-gray-300'
                }`}
              >
                <span className="text-3xl mb-1">{opt.emoji}</span>
                <span>{opt.title}</span>
                <span className={`text-xs font-semibold mt-1 ${fulfillmentType === opt.key ? 'text-tomato' : 'text-gray-400'}`}>
                  {opt.sub}
                </span>
              </button>
            ))}
          </div>

          {fulfillmentType === 'pickup' && (
            <div className="mt-3 bg-blue-50 rounded-xl p-3 text-xs text-navy font-medium flex items-center gap-2">
              <span>📍</span>
              <span>{he.store_address}</span>
            </div>
          )}
        </div>

        {/* STEP 2: Contact */}
        <div className="bg-white rounded-2xl shadow-sm p-4 space-y-3">
          <p className="text-xs font-bold text-gray-400 uppercase tracking-wider">שלב 2 — פרטי קשר</p>

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-1">{he.name}</label>
            <input
              name="name"
              value={form.name}
              onChange={handleChange}
              required
              placeholder="שם מלא"
              className="w-full border-2 border-gray-100 rounded-xl px-4 py-3 focus:outline-none focus:border-tomato transition text-gray-800 bg-gray-50"
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-1">{he.phone}</label>
            <input
              name="phone"
              type="tel"
              value={form.phone}
              onChange={handleChange}
              required
              placeholder="050-0000000"
              dir="ltr"
              className="w-full border-2 border-gray-100 rounded-xl px-4 py-3 focus:outline-none focus:border-tomato transition text-gray-800 bg-gray-50"
            />
          </div>

          {fulfillmentType === 'delivery' && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-1">{he.address}</label>
              <input
                name="address"
                value={form.address}
                onChange={handleChange}
                required
                placeholder="רחוב, מספר, עיר"
                className="w-full border-2 border-gray-100 rounded-xl px-4 py-3 focus:outline-none focus:border-tomato transition text-gray-800 bg-gray-50"
              />
              {addressPrefilled && (
                <p className="text-xs text-green-500 mt-1 font-medium">✓ מולאה מהזמנה קודמת</p>
              )}
            </div>
          )}
        </div>

        {/* STEP 3: Notes */}
        <div className="bg-white rounded-2xl shadow-sm p-4 space-y-3">
          <p className="text-xs font-bold text-gray-400 uppercase tracking-wider">שלב 3 — הערות (אופציונלי)</p>

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-1">{he.kitchen_notes}</label>
            <textarea
              name="kitchenNotes"
              value={form.kitchenNotes}
              onChange={handleChange}
              rows={2}
              placeholder="לדוגמה: ללא גלוטן, לא חריף..."
              className="w-full border-2 border-gray-100 rounded-xl px-4 py-3 focus:outline-none focus:border-tomato transition resize-none text-sm bg-gray-50"
            />
          </div>

          {fulfillmentType === 'delivery' && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-1">{he.driver_notes}</label>
              <textarea
                name="driverNotes"
                value={form.driverNotes}
                onChange={handleChange}
                rows={2}
                placeholder="לדוגמה: קומה 3, אינטרקום 12..."
                className="w-full border-2 border-gray-100 rounded-xl px-4 py-3 focus:outline-none focus:border-tomato transition resize-none text-sm bg-gray-50"
              />
            </div>
          )}
        </div>

        {/* STEP 4: Payment */}
        <div className="bg-white rounded-2xl shadow-sm p-4">
          <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-3">שלב 4 — תשלום</p>
          <div className="grid grid-cols-2 gap-3">
            {[
              { key: 'cash',   emoji: '💵', title: fulfillmentType === 'pickup' ? 'מזומן בעסק' : 'מזומן לשליח' },
              { key: 'credit', emoji: '💳', title: 'כרטיס אשראי' },
            ].map(opt => (
              <label
                key={opt.key}
                className={`flex flex-col items-center justify-center py-5 rounded-xl border-2 cursor-pointer font-bold text-sm transition ${
                  form.paymentMethod === opt.key
                    ? 'border-tomato bg-red-50 text-tomato shadow-sm'
                    : 'border-gray-200 text-gray-500 hover:border-gray-300'
                }`}
              >
                <input type="radio" name="paymentMethod" value={opt.key}
                  checked={form.paymentMethod === opt.key}
                  onChange={handleChange} className="hidden" />
                <span className="text-3xl mb-1">{opt.emoji}</span>
                <span>{opt.title}</span>
              </label>
            ))}
          </div>
          {form.paymentMethod === 'cash' && (
            <p className="text-xs text-gray-400 mt-2 text-center">
              התשלום בעת {fulfillmentType === 'pickup' ? 'האיסוף' : 'קבלת ההזמנה'}
            </p>
          )}
        </div>

        {/* Promo Code */}
        <div className="bg-white rounded-2xl shadow-sm p-4">
          <button
            type="button"
            className="w-full flex items-center justify-between text-sm font-bold text-gray-700"
            onClick={() => setShowPromo(s => !s)}
          >
            <span>🏷️ {he.promo_code}</span>
            <span className="text-gray-400">{showPromo ? '▲' : '▼'}</span>
          </button>

          {showPromo && (
            <div className="mt-3">
              {appliedPromo ? (
                <div className="flex items-center gap-2 bg-green-50 border border-green-200 rounded-xl px-3 py-2.5">
                  <span className="text-green-700 text-sm font-bold flex-1">
                    ✓ {appliedPromo.label} ({appliedPromo.code})
                  </span>
                  <button type="button" onClick={removePromo} className="text-gray-400 text-xs hover:text-red-500">
                    הסר
                  </button>
                </div>
              ) : (
                <div className="flex gap-2">
                  <input
                    value={promoInput}
                    onChange={e => { setPromoInput(e.target.value); setPromoError(''); }}
                    onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), applyPromo())}
                    placeholder="הכנס קוד..."
                    className="flex-1 border-2 border-gray-100 rounded-xl px-3 py-2.5 focus:outline-none focus:border-tomato transition text-sm uppercase bg-gray-50"
                    dir="ltr"
                  />
                  <button
                    type="button"
                    onClick={applyPromo}
                    className="bg-navy text-white px-4 rounded-xl text-sm font-bold transition hover:opacity-90"
                  >
                    החל
                  </button>
                </div>
              )}
              {promoError && <p className="text-red-500 text-xs mt-1">{promoError}</p>}
              <p className="text-xs text-gray-400 mt-1">PIZZA10 | PIZZA20 | FREESHIP</p>
            </div>
          )}
        </div>

        {/* Price Summary */}
        <div className="bg-navy rounded-2xl p-4 space-y-2">
          <div className="flex justify-between text-sm text-white/70">
            <span>🍕 פיצה + תוספות</span>
            <span>{baseTotal}₪</span>
          </div>
          {fulfillmentType === 'delivery' && (
            <div className="flex justify-between text-sm text-white/70">
              <span>🛵 דמי משלוח</span>
              <span>
                {isFreeShip ? (
                  <span className="flex items-center gap-1">
                    <span className="line-through opacity-50">{DELIVERY_FEE}₪</span>
                    <span className="text-green-300 font-bold">חינם!</span>
                  </span>
                ) : `${DELIVERY_FEE}₪`}
              </span>
            </div>
          )}
          {discountAmt > 0 && (
            <div className="flex justify-between text-sm text-green-300 font-medium">
              <span>🏷️ הנחה ({appliedPromo.code})</span>
              <span>-{discountAmt}₪</span>
            </div>
          )}
          <div className="flex justify-between items-center pt-2 border-t border-white/20">
            <span className="text-white font-black text-lg">סה"כ לתשלום</span>
            <span className="text-white font-black text-2xl">{finalTotal}₪</span>
          </div>
        </div>

        {/* Submit */}
        <button
          type="submit"
          disabled={loading}
          className="w-full bg-tomato text-white py-5 rounded-2xl font-black text-xl shadow-md hover:bg-red-700 transition active:scale-95 disabled:opacity-60"
        >
          {loading ? '⏳ שולח הזמנה...' : `✅ בצע הזמנה • ${finalTotal}₪`}
        </button>
      </div>
    </form>
  );
}
